import React, { useState } from 'react';
import { X, ClipboardCheck, MessageSquare, Send } from 'lucide-react';
import '../interviewer/css/EvaluationModal.css';

const EvaluationModal = ({ booking, onClose, onSuccess }) => {
    const [formData, setFormData] = useState({
        report: '',
        annotations: ''
    });
    const [isSubmitting, setIsSubmitting] = useState(false);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setIsSubmitting(true);
        try {
            await api.post(`/v1/interviewer/booking/${booking.id}/evaluation`, {
                report: formData.report,
                annotations: formData.annotations
            });
            onSuccess();
            onClose();
        } catch (err) {
            alert("Failed to submit evaluation: " + (err.response?.data?.message || "Error"));
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="modal-overlay">
            <div className="modal-content evaluation-modal">
                {/* Header */}
                <div className="modal-header">
                    <div className="header-content">
                        <div className="icon-circle">
                            <ClipboardCheck size={28} />
                        </div>
                        <div>
                            <h2>Submit Interview Evaluation</h2>
                            <p className="subtitle">Candidate: {booking.candidateName || 'Candidate'}</p>
                        </div>
                    </div>
                    <button className="close-btn" onClick={onClose}>
                        <X size={24} />
                    </button>
                </div>

                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label>
                            <MessageSquare size={18} />
                            Performance Report <span className="required">*</span>
                        </label>
                        <textarea
                            required
                            placeholder="Share detailed feedback about the candidate's performance, strengths, and areas of improvement..."
                            value={formData.report}
                            onChange={(e) => setFormData({ ...formData, report: e.target.value })}
                            rows={7}
                        />
                    </div>

                    <div className="form-group">
                        <label>
                            <Send size={18} />
                            Private Annotations
                        </label>
                        <textarea
                            placeholder="Technical notes, score breakdown, red flags, or any internal observations..."
                            value={formData.annotations}
                            onChange={(e) => setFormData({ ...formData, annotations: e.target.value })}
                            rows={5}
                        />
                        <p className="helper-text">Visible only to your team</p>
                    </div>

                    <div className="modal-actions">
                        <button type="button" className="btn-cancel" onClick={onClose}>
                            Cancel
                        </button>
                        <button 
                            type="submit" 
                            className="btn-submit"
                            disabled={isSubmitting}
                        >
                            {isSubmitting ? "Submitting Evaluation..." : "Complete & Submit Evaluation"}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default EvaluationModal;
